/**
 * Clear menu cache for a vendor
 */
export const clearMenuCache = (vendorId) => {
  try {
    const cacheKey = `${CACHE_KEY_PREFIX}${vendorId}`;
    localStorage.removeItem(cacheKey);
    console.log(`🗑️ Cleared menu cache for vendor ${vendorId}`);
  } catch (error) {
    console.error('Error clearing menu cache:', error);
  }
};

/**
 * Get popular items from a vendor's menu
 */
export const getPopularItems = (menuData, count = 5) => {
  if (!menuData || !menuData.menu) return [];
  
  const allItems = Object.values(menuData.menu).flat();
  return allItems.slice(0, count);
};

/**
 * Search menu items
 */
export const searchMenuItems = (menuData, query) => {
  if (!menuData || !menuData.menu || !query) return [];
  
  const searchTerm = query.toLowerCase();
  const allItems = Object.values(menuData.menu).flat();
  
  return allItems.filter(item => 
    item.name.toLowerCase().includes(searchTerm) ||
    item.description.toLowerCase().includes(searchTerm)
  );
};

export default {
  getVendorMenu,
  fetchVendorMenu,
  createVendorOrder,
  getVendorInfo,
  getConnectedVendors,
  clearMenuCache,
  getPopularItems,
  searchMenuItems
}; 